def td_tic_tac_toe(games: list, alpha: float = 0.1, initial_value: float = 0.5) -> dict:
    """
    Learn Tic-Tac-Toe state values using TD(0) from recorded games.
    """
    values = {}

    for game in games:
        states = game['states']
        result = game['result']
        n = len(states)

        # Iterate over non-terminal states only (all except the last)
        for i in range(n - 1):
            state = states[i]
            next_state = states[i + 1]

            # Lazily initialize current non-terminal state
            if state not in values:
                values[state] = initial_value

            # Determine the TD target:
            # If next_state is the terminal state (last in sequence), use the game result.
            # Otherwise use (or initialize) the stored value of next_state.
            if i + 1 == n - 1:
                target = result
            else:
                if next_state not in values:
                    values[next_state] = initial_value
                target = values[next_state]

            # TD(0) update: V(s) <- V(s) + alpha * (target - V(s))
            values[state] += alpha * (target - values[state])

    return {state: round(v, 4) for state, v in values.items()}

