import numpy as np

def td_tic_tac_toe(games: list, alpha: float = 0.1, initial_value: float = 0.5) -> dict:
    """
    TD(0) for Tic-Tac-Toe using NumPy float64 for value storage.
    NumPy adds precision control and vectorised batch-update capability.
    """
    # Store values as numpy float64 for numerical consistency
    values: dict = {}

    for game in games:
        states = game['states']
        result = np.float64(game['result'])
        n = len(states)

        for i in range(n - 1):
            state = states[i]
            next_state = states[i + 1]

            if state not in values:
                values[state] = np.float64(initial_value)

            if i + 1 == n - 1:
                target = result
            else:
                if next_state not in values:
                    values[next_state] = np.float64(initial_value)
                target = values[next_state]

            # TD(0) update using numpy arithmetic
            td_error = target - values[state]
            values[state] += np.float64(alpha) * td_error

    return {state: float(np.round(v, 4)) for state, v in values.items()}


def td_tic_tac_toe_batch(games: list, alpha: float = 0.1, initial_value: float = 0.5) -> dict:
    """
    Batch variant: collects all (state, target) pairs first, then applies
    vectorised TD updates using NumPy arrays. Useful when games are pre-recorded
    and you want to sweep the dataset multiple times efficiently.
    """
    # Build state index
    state_index: dict = {}

    def get_idx(s):
        if s not in state_index:
            state_index[s] = len(state_index)
        return state_index[s]

    # Collect (state_idx, target_idx_or_result, is_terminal_target) triples
    transitions = []  # (s_idx, next_s_idx_or_-1, terminal_result_or_NaN)

    for game in games:
        states = game['states']
        result = game['result']
        n = len(states)
        for i in range(n - 1):
            s_idx = get_idx(states[i])
            if i + 1 == n - 1:
                transitions.append((s_idx, -1, result))
            else:
                ns_idx = get_idx(states[i + 1])
                transitions.append((s_idx, ns_idx, np.nan))

    # Initialise value array
    n_states = len(state_index)
    V = np.full(n_states, initial_value, dtype=np.float64)

    # Sequential TD(0) updates (order matters — cannot fully vectorise here
    # without losing the within-episode dependency, but numpy ops are faster)
    alpha_np = np.float64(alpha)
    for s_idx, ns_idx, term_result in transitions:
        target = np.float64(term_result) if ns_idx == -1 else V[ns_idx]
        V[s_idx] += alpha_np * (target - V[s_idx])

    # Build output dict, excluding any state that only appeared as terminal
    # (those were never added to state_index as non-terminal)
    idx_to_state = {v: k for k, v in state_index.items()}
    return {idx_to_state[i]: float(np.round(V[i], 4)) for i in range(n_states)}
